package com.company.supervision.application.organization;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;import com.company.supervision.domain.model.organization.*;import com.company.supervision.infrastructure.repository.organization.*;import com.company.supervision.infrastructure.security.SecretCipher;import com.company.supervision.infrastructure.security.SensitiveDataRedactor;import com.fasterxml.jackson.databind.JsonNode;import org.springframework.data.redis.core.StringRedisTemplate;import org.springframework.http.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.web.client.RestTemplate;import java.time.*;import java.util.*;import java.util.concurrent.TimeUnit;
@Service public class WecomIntegrationService{
 private final WecomConfigMapper configs;private final DepartmentMapper departments;private final PersonMapper persons;private final PersonDepartmentMapper links;private final OrgSyncLogMapper logs;private final SecretCipher cipher;private final StringRedisTemplate redis;private final RestTemplate http;
 public WecomIntegrationService(WecomConfigMapper c,DepartmentMapper d,PersonMapper p,PersonDepartmentMapper l,OrgSyncLogMapper g,SecretCipher s,StringRedisTemplate r,RestTemplate h){configs=c;departments=d;persons=p;links=l;logs=g;cipher=s;redis=r;http=h;}
 public Map<String,Object> getConfig(){WecomConfig c=configs.byTenant("default");if(c==null)return Map.of("tenantKey","default","configured",false);Map<String,Object>m=new LinkedHashMap<>();m.put("id",c.getId());m.put("tenantKey",c.getTenantKey());m.put("corpId",c.getCorpId());m.put("agentId",c.getAgentId());m.put("directorySecret",cipher.mask(c.getDirectorySecretCipher()));m.put("appSecret",cipher.mask(c.getAppSecretCipher()));m.put("configured",c.getDirectorySecretCipher()!=null);m.put("lastVerifiedAt",c.getLastVerifiedAt());m.put("lastSyncAt",c.getLastSyncAt());return m;}
 public void save(Map<String,Object>m){WecomConfig c=configs.byTenant("default");if(c==null){c=new WecomConfig();c.setTenantKey("default");}c.setCorpId(str(m,"corpId"));c.setAgentId(m.get("agentId")==null?null:Integer.valueOf(m.get("agentId").toString()));if(has(m,"directorySecret"))c.setDirectorySecretCipher(cipher.encrypt(str(m,"directorySecret")));if(has(m,"appSecret"))c.setAppSecretCipher(cipher.encrypt(str(m,"appSecret")));c.setStatus(1);if(c.getId()==null)configs.insert(c);else configs.updateById(c);redis.delete("supervision:wecom:token:default");}
 public Map<String,Object> verify(){WecomConfig c=required();String token=token(c,true);c.setLastVerifiedAt(LocalDateTime.now());configs.updateById(c);return Map.of("success",true,"corpId",c.getCorpId(),"tokenAvailable",token!=null);}
 public Integer agentId(){WecomConfig c=required();if(c.getAgentId()==null)throw new IllegalStateException("WeCom application AgentId is not configured");return c.getAgentId();}
 public String token(boolean directory){return token(required(),directory);} private String token(WecomConfig c,boolean directory){String key="supervision:wecom:token:"+(directory?"directory":"app");String cached=redis.opsForValue().get(key);if(cached!=null)return cached;String secret=cipher.decrypt(directory?c.getDirectorySecretCipher():c.getAppSecretCipher());JsonNode n=http.getForObject("https://qyapi.weixin.qq.com/cgi-bin/gettoken?corpid={corp}&corpsecret={secret}",JsonNode.class,c.getCorpId(),secret);if(n==null||n.path("errcode").asInt()!=0)throw new IllegalStateException("WeCom token failed: "+(n==null?"empty":n.path("errmsg").asText()));String t=n.path("access_token").asText();redis.opsForValue().set(key,t,Math.max(60,n.path("expires_in").asLong(7200)-300),TimeUnit.SECONDS);return t;}
 @Transactional public Map<String,Object> sync(Long operator){String lock="supervision:wecom:sync:lock";if(!Boolean.TRUE.equals(redis.opsForValue().setIfAbsent(lock,"1",30,TimeUnit.MINUTES)))throw new IllegalStateException("Synchronization already running");OrgSyncLog log=new OrgSyncLog();log.setTenantKey("default");log.setOperatorId(operator);log.setStatus("RUNNING");log.setStartedAt(LocalDateTime.now());logs.insert(log);try{WecomConfig cfg=required();String token=token(cfg,true);JsonNode depResp=http.getForObject("https://qyapi.weixin.qq.com/cgi-bin/department/list?access_token={token}",JsonNode.class,token);check(depResp);List<Department>seenDeps=new ArrayList<>();for(JsonNode n:depResp.path("department")){Department d=departments.byExternal("default",n.path("id").asLong());if(d==null){d=new Department();d.setTenantKey("default");d.setWecomDepartmentId(n.path("id").asLong());}d.setParentWecomDepartmentId(n.path("parentid").asLong());d.setName(n.path("name").asText());d.setOrderNo(n.path("order").asInt());d.setStatus(1);d.setSyncedAt(LocalDateTime.now());if(d.getId()==null)departments.insert(d);else departments.updateById(d);seenDeps.add(d);}JsonNode users=http.getForObject("https://qyapi.weixin.qq.com/cgi-bin/user/list?access_token={token}&department_id=1&fetch_child=1",JsonNode.class,token);check(users);Set<String>seenUsers=new HashSet<>();int pc=0;for(JsonNode n:users.path("userlist")){String uid=n.path("userid").asText();seenUsers.add(uid);Person p=persons.byExternal("default",uid);if(p==null){p=new Person();p.setTenantKey("default");p.setWecomUserId(uid);}p.setName(n.path("name").asText());p.setMobileMasked(maskMobile(n.path("mobile").asText()));p.setEmail(n.path("email").asText());p.setPositionName(n.path("position").asText());p.setAvatarUrl(n.path("avatar").asText());p.setGender(switch(n.path("gender").asInt(0)){case 1->"MALE";case 2->"FEMALE";default->"UNKNOWN";});p.setStatus(1);p.setSyncStatus("SUCCESS");p.setSyncErrorRedacted(null);p.setSyncedAt(LocalDateTime.now());if(p.getId()==null)persons.insert(p);else persons.updateById(p);links.deleteForPerson(p.getId());int i=0;for(JsonNode did:n.path("department")){Department d=departments.byExternal("default",did.asLong());if(d!=null){if(i==0)p.setPrimaryDepartmentId(d.getId());links.link(p.getId(),d.getId(),i++==0?1:0);}}persons.updateById(p);pc++;}persons.update(null,new LambdaUpdateWrapper<Person>().eq(Person::getTenantKey,"default").notIn(!seenUsers.isEmpty(),Person::getWecomUserId,seenUsers).set(Person::getStatus,0));log.setStatus("SUCCESS");log.setDepartmentCount(seenDeps.size());log.setPersonCount(pc);log.setEndedAt(LocalDateTime.now());logs.updateById(log);cfg.setLastSyncAt(LocalDateTime.now());configs.updateById(cfg);return Map.of("departments",seenDeps.size(),"persons",pc,"status","SUCCESS");}catch(Exception e){log.setStatus("FAILED");log.setErrorDetail(SensitiveDataRedactor.redact(e.getMessage()));log.setEndedAt(LocalDateTime.now());logs.updateById(log);throw e;}finally{redis.delete(lock);}}
 public List<Department> departmentTree(){return departments.selectList(new LambdaQueryWrapper<Department>().eq(Department::getStatus,1).orderByAsc(Department::getOrderNo));}public List<Person> people(String name){LambdaQueryWrapper<Person>w=new LambdaQueryWrapper<Person>().eq(Person::getStatus,1);if(name!=null&&!name.isBlank())w.like(Person::getName,name);return persons.selectList(w.orderByAsc(Person::getName));}public List<OrgSyncLog> syncLogs(){return logs.selectList(new LambdaQueryWrapper<OrgSyncLog>().orderByDesc(OrgSyncLog::getId).last("LIMIT 100"));}
 private WecomConfig required(){WecomConfig c=configs.byTenant("default");if(c==null||c.getCorpId()==null||c.getDirectorySecretCipher()==null)throw new IllegalStateException("WeCom directory configuration is incomplete");return c;}private void check(JsonNode n){if(n==null||n.path("errcode").asInt()!=0)throw new IllegalStateException("WeCom API failed: "+(n==null?"empty":n.path("errmsg").asText()));}private static boolean has(Map<String,Object>m,String k){Object v=m.get(k);return v!=null&&!v.toString().isBlank()&&!v.toString().equals("******");}private static String str(Map<String,Object>m,String k){return m.get(k)==null?null:m.get(k).toString();}private static String maskMobile(String v){return v==null||v.length()<4?null:"*******"+v.substring(v.length()-4);}
}